{
  "file": "backend/pipeline/nodes/clarify.py",
  "summary": "This file contains logic for detecting ambiguities in a Solution Design Document (SDD) using an AI model. It constructs a prompt and context for the AI to review, then parses its response to determine if any clarifications are needed before proceeding with story generation.",
  "rules": [
    {
      "name": "clarify_node",
      "description": "Asks Claude to identify ambiguities in the SDD based on predefined categories; updates state accordingly.",
      "conditions": ["state contains retrieved context and solution doc text"],
      "actions": ["builds prompt for AI review", "parses AI response for ambiguities", "updates state with clarification status"]
    }
  ],
  "dependencies": ["config.settings", "pipeline.nodes.json_response.extract_json", "pipeline.nodes.json_response.extract_text", "pipeline.state.StoryForgeState", "langchain_anthropic.ChatAnthropic", "langchain_core.messages.HumanMessage", "langchain_core.messages.SystemMessage"]
}
